                messages: Vec::new(),
                queue: Vec::new(),
                politeness: props.politeness,
                atomic: props.atomic,
                relevant: props.relevant.clone(),
                delay: props.delay,
                pending_message: None,
                current_priority: AnnouncePriority::Normal,
            },
        )
    }

