461	fn clear_plan(target: State) -> TransitionPlan<Machine> {
462	    TransitionPlan::to(target)
463	        .apply(|ctx: &mut Context| {
464	            ctx.messages.clear();
465	            ctx.queue.clear();
466	            ctx.pending_message = None;
467	            ctx.current_priority = AnnouncePriority::Normal;
468	        })
469	        .cancel_effect(Effect::AnnounceDelay)
470	}
471	
472	const fn has_announcements(ctx: &Context) -> bool {
473	    !ctx.messages.is_empty() || !ctx.queue.is_empty() || ctx.pending_message.is_some()
474	}
475	
476	fn announce_delay_effect() -> PendingEffect<Machine> {
477	    PendingEffect::named(Effect::AnnounceDelay)
478	}
479	
480	fn next_sequence(queue: &[QueuedAnnouncement]) -> u64 {
481	    queue
482	        .iter()
483	        .map(|announcement| announcement.sequence)
484	        .max()
485	        .map_or(0, |sequence| sequence.saturating_add(1))
486	}
487	
488	fn dequeue_next(queue: &mut Vec<QueuedAnnouncement>) -> Option<QueuedAnnouncement> {
489	    let index = queue
490	        .iter()
491	        .enumerate()
492	        .min_by_key(|(_, announcement)| {
493	            (
494	                priority_sort_key(announcement.priority),
495	                announcement.sequence,
496	            )
497	        })
498	        .map(|(index, _)| index)?;
499	
500	    Some(queue.remove(index))
501	}
502	
503	const fn priority_sort_key(priority: AnnouncePriority) -> u8 {
504	    match priority {
505	        AnnouncePriority::Urgent => 0,
506	        AnnouncePriority::Normal => 1,
507	    }
508	}
