184	use ars_core::{TransitionPlan, PendingEffect, ConnectApi, AttrMap};
185	
186	/// The machine for the `FocusScope` component.
187	pub struct Machine;
188	
189	/// This component has no translatable strings.
190	#[derive(Clone, Debug, Default, PartialEq)]
191	pub struct Messages;
192	impl ComponentMessages for Messages {}
193	
194	impl ars_core::Machine for Machine {
195	    type State = State;
196	    type Event = Event;
197	    type Context = Context;
198	    type Props = Props;
199	    type Messages = Messages;
200	    type Api<'a> = Api<'a>;
201	
202	    fn init(props: &Props, _env: &Env, _messages: &Messages) -> (State, Context) {
203	        (
204	            State::Inactive,
205	            Context {
206	                saved_focus: None,
207	                container_id: None,
208	            },
209	        )
210	    }
211	
212	    fn transition(
213	        state: &Self::State,
214	        event: &Self::Event,
215	        ctx: &Self::Context,
216	        props: &Self::Props,
217	    ) -> Option<TransitionPlan<Self>> {
218	        match (state, event) {
219	            // ── Activation ──────────────────────────────────────────────
220	            (State::Inactive, Event::Activate { trapped, saved_focus_id }) => {
221	                let trap = *trapped || props.contain;
222	                let auto_focus = props.auto_focus;
223	                let saved = saved_focus_id.clone();
224	                let mut plan = TransitionPlan::to(State::Active { trapped: trap })
225	                    .apply(move |ctx| {
226	                        ctx.saved_focus = saved;
227	                    })
228	                    .with_named_effect("focus-trap-listener", |ctx, _props, send| {
229	                        let platform = use_platform_effects();
230	                        let container_id = ctx.ids.part("container");
231	                        platform.attach_focus_trap(&container_id, Box::new(move || {
232	                            send.call_if_alive(Event::Deactivate { restore_focus: true });
233	                        }))
234	                    });
235	                if auto_focus {
236	                    plan = plan.then(Event::FocusFirst);
237	                }
238	                Some(plan)
239	            }
240	
241	            // ── Deactivation ────────────────────────────────────────────
242	            (State::Active { .. }, Event::Deactivate { restore_focus }) => {
243	                let restore = *restore_focus;
244	                let mut plan = TransitionPlan::to(State::Inactive);
245	                if restore {
246	                    // RestoreFocus will read saved_focus then clear it.
247	                    plan = plan.then(Event::RestoreFocus);
248	                } else {
249	                    plan = plan.apply(|ctx| {
250	                        ctx.saved_focus = None; // Clear to prevent stale DOM references
251	                    });
252	                }
253	                Some(plan)
254	            }
255	
256	            // ── Trap / Release ──────────────────────────────────────────
257	            (State::Active { trapped: false }, Event::TrapFocus) => {
258	                Some(TransitionPlan::to(State::Active { trapped: true }))
