    /// Request that focus move to the last tabbable descendant of the
    /// container. Sends [`Event::FocusLast`].
    pub fn focus_last(&self) {
        (self.send)(Event::FocusLast);
    }

    /// Move focus to the next focusable element within the scope.
    ///
    /// Returns `true` if focus was moved, `false` otherwise. The agnostic
    /// core cannot resolve tabbable elements synchronously and returns
    /// `false` as its stable contract — adapters layer a platform-aware
    /// variant on top (used by `Toolbar`, `ActionGroup`, `TreeView`).
    #[must_use]
    pub const fn focus_next(&self, _opts: &FocusNavigationOptions) -> bool {
        false
    }

    /// Move focus to the previous focusable element within the scope.
    ///
    /// Returns `true` if focus was moved, `false` otherwise. Adapter-
    /// overridable; see [`focus_next`](Self::focus_next).
    #[must_use]
    pub const fn focus_previous(&self, _opts: &FocusNavigationOptions) -> bool {
        false
    }
}

