// ────────────────────────────────────────────────────────────────────
// FocusNavigationOptions
// ────────────────────────────────────────────────────────────────────

/// Reference-counted predicate filter used by [`FocusNavigationOptions::accept`].
///
/// Wrapping the trait object in [`Rc`] keeps [`FocusNavigationOptions`]
/// trivially [`Clone`] while letting consumers share the predicate
/// across multiple calls without re-allocating.
pub type AcceptFn = Rc<dyn Fn(&str) -> bool>;

/// Options for adapter-provided focus navigation.
///
/// The agnostic core only carries the option payload; behavior lives in
/// each adapter's platform-aware override of [`Api::focus_next`] and
/// [`Api::focus_previous`].
#[derive(Clone)]
pub struct FocusNavigationOptions {
    /// Wrap around at boundaries.
    pub wrap: bool,
    /// Element ID to start from (default: currently focused element).
    pub from: Option<String>,
    /// Only consider tabbable elements (`tabindex >= 0`).
    pub tabbable: bool,
    /// Custom filter predicate that receives an element ID.
    pub accept: Option<AcceptFn>,
}

impl Debug for FocusNavigationOptions {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("FocusNavigationOptions")
            .field("wrap", &self.wrap)
            .field("from", &self.from)
            .field("tabbable", &self.tabbable)
            .field("accept", &self.accept.as_ref().map(|_| "<predicate>"))
            .finish()
    }
}

impl Default for FocusNavigationOptions {
    fn default() -> Self {
        Self {
            wrap: false,
            from: None,
            tabbable: true,
            accept: None,
        }
    }
}

