fn focus_navigation_options_default_and_debug_are_inert() {
    let opts = FocusNavigationOptions::default();
    assert!(!opts.wrap);
    assert!(opts.tabbable);
    assert!(opts.from.is_none());
    assert!(opts.accept.is_none());

    let formatted = format!("{opts:?}");
    assert!(formatted.contains("FocusNavigationOptions"));

    // A populated `accept` predicate must format as `<predicate>` so
    // the printed structure stays stable even when the closure is not
