    let with_predicate = FocusNavigationOptions {
        accept: Some(Rc::new(|_: &str| true)),
        ..FocusNavigationOptions::default()
    };
    let formatted = format!("{with_predicate:?}");
    assert!(formatted.contains("<predicate>"));
}

